import{_ as s,o as a,c as i,ae as t}from"./chunks/framework.BMBGeRFM.js";const u=JSON.parse('{"title":"Setting Up Farben","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pre-requisites/index.md","filePath":"guide/pre-requisites/index.md"}'),n={name:"guide/pre-requisites/index.md"};function o(r,e,l,h,p,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="setting-up-farben" tabindex="-1">Setting Up Farben <a class="header-anchor" href="#setting-up-farben" aria-label="Permalink to &quot;Setting Up Farben&quot;">​</a></h1><p>Every adventure has a starting point, so does every rabbit hole -- even shallow ones! In this adventure (or rabbit hole, depends on you), we start at humble beginnings, since Farben is already published on <a href="https://crates.io/crates/farben" target="_blank" rel="noreferrer">Crates.io</a>.</p><p>So, you want to color your terminal without touching this abomination: <code>\\x1b[31m</code>? Farben got you covered. With markup-like syntax <code>[bold red]</code>, you can learn Farben in <strong>seconds</strong>.</p><h2 id="making-a-new-project" tabindex="-1">Making A New Project <a class="header-anchor" href="#making-a-new-project" aria-label="Permalink to &quot;Making A New Project&quot;">​</a></h2><p>Let&#39;s start by creating your first Rust project using Cargo. Install Cargo somewhere, I don&#39;t care where, and run the following command:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-cool-farben-project</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-cool-farben-project</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Change <code>my-cool-farben-project</code> to whatever you want.</p></div><p>You should see a classic Cargo project file structure -- <code>src/main.rs</code>, <code>Cargo.toml</code>, <code>Cargo.lock</code>, and <code>.gitignore</code>. Add whatever you&#39;ll need there before moving on.</p><h2 id="adding-farben" tabindex="-1">Adding Farben <a class="header-anchor" href="#adding-farben" aria-label="Permalink to &quot;Adding Farben&quot;">​</a></h2><p>Let&#39;s add Farben to your project. Since you&#39;re using Cargo, this process should be straightforward and easy, as easy as running this command:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> farben</span></span></code></pre></div><p>Run it, wait, and once it&#39;s done, you&#39;re set! Alternatively, you can add the version manually to your <code>Cargo.toml</code>:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dependencies</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">farben = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;insert.version.here&quot;</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To search the versions, visit the <a href="https://crates.io/crates/farben" target="_blank" rel="noreferrer">Crates.io</a> page for this project.</p></div><p>To start, change the code inside <code>main.rs</code> to the following:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> farben</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">prelude</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    cprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[bold blue]Hello, [italic cyan]world!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="opting-in-to-compiling" tabindex="-1">Opting-in to Compiling <a class="header-anchor" href="#opting-in-to-compiling" aria-label="Permalink to &quot;Opting-in to Compiling&quot;">​</a></h2><p>Farben has this neat feature called <code>compile</code>, which parses your soon-to-be colored text <em>in compilation</em>, not runtime. This makes for <strong>zero runtime overhead</strong>, and <strong>compile-time errors</strong> instead of unexpected runtime panics. I&#39;m not saying you <em>should</em>, but yeah, you should enable this feature, by running this command instead of <code>cargo add farben</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> farben</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --features</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span></span></code></pre></div><h3 id="what-s-the-catch" tabindex="-1">What&#39;s the Catch? <a class="header-anchor" href="#what-s-the-catch" aria-label="Permalink to &quot;What&#39;s the Catch?&quot;">​</a></h3><p>There HAS to be a catch, right? All these benefits and no catch? Well, there&#39;s not much. The only change when you enable this feature is that <code>color()</code> (a function) becomes <code>color!()</code> (a macro). But that doesn&#39;t matter, since we&#39;ll be using <code>cprintln!()</code> anyway.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>It also introduces a new dependency -- <code>farben-macros</code>, but you don&#39;t have to worry about it.</p></div><details class="details custom-block"><summary>Details</summary><p>The thing you should note though: &quot;Zero runtime overhead&quot; only applies to the <code>color!()</code> macro, which takes a fixed, non-formatted string. This doesn&#39;t mean there&#39;s no benefits though, as the other functions you&#39;ll be seeing will have <em>compile-time validation</em>, which is still a worth-it feature.</p></details><div class="info custom-block"><p class="custom-block-title">INFO</p><p>In the newest version of Farben, version 0.4; <code>cprintln!()</code>, <code>cprint!()</code>, <code>cprintbln!()</code>, and <code>cprintb!()</code> supports compile-time parsing, that is if you pass in a static string. Huge win for the Rustaceans!</p></div><hr><p>Now that you got Farben all set up, Let&#39;s. Get. Coloring!</p>`,26)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
